CREATE OR REPLACE FUNCTION apply_field_transform(p_value JSONB, p_transform_type TEXT, p_transform_params TEXT)
RETURNS JSONB
LANGUAGE plpgsql
AS $$
DECLARE
    params JSONB;
    input_format TEXT;
    output_format TEXT;
    parsed_date DATE;
    text_val TEXT;
BEGIN
    IF p_value IS NULL OR jsonb_typeof(p_value) = 'null' THEN
        RETURN p_value;
    END IF;

    IF p_transform_type IS NULL OR p_transform_type = 'none' THEN
        RETURN p_value;
    END IF;

    IF p_transform_type = 'uppercase' THEN
        RETURN to_jsonb(upper(p_value #>> '{}'));
    END IF;

    IF p_transform_type = 'lowercase' THEN
        RETURN to_jsonb(lower(p_value #>> '{}'));
    END IF;

    IF p_transform_type = 'date_format' THEN
        text_val := p_value #>> '{}';
        IF text_val IS NULL OR text_val = '' THEN
            RETURN p_value;
        END IF;

        params := NULLIF(p_transform_params, '')::JSONB;
        input_format := COALESCE(params ->> 'inputFormat', 'YYYY-MM-DD');
        output_format := COALESCE(params ->> 'outputFormat', 'YYYY-MM-DD');

        BEGIN
            parsed_date := to_date(text_val, input_format);
        EXCEPTION WHEN OTHERS THEN
            RETURN p_value;
        END;

        RETURN to_jsonb(to_char(parsed_date, output_format));
    END IF;

    -- 'lookup' and 'calculate' are not implemented locally (no lookup-table storage,
    -- no expression evaluator) -- fall through to the raw value rather than erroring.
    RETURN p_value;
END;
$$;
